!function(){const n=document.getElementById("lgp-company-map");if(!n||!window.lgpCompanyMap||!Array.isArray(window.lgpCompanyMap.markers))return;const{markers:t,tileUrl:o,tileAttribution:a}=window.lgpCompanyMap,e=L.map(n,{scrollWheelZoom:!1});if(L.tileLayer(o,{attribution:a}).addTo(e),!t.length)return void e.setView([39.5,-98.35],4);const r=L.layerGroup().addTo(e);t.forEach(n=>{if("number"!=typeof n.lat||"number"!=typeof n.lng)return;const t=`<strong>${n.name||"Company"}</strong>`+(n.type?`<br><em>${n.type}</em>`:"");L.marker([n.lat,n.lng]).bindPopup(t).addTo(r)});const p=L.latLngBounds(t.map(n=>[n.lat,n.lng]));e.fitBounds(p.pad(.15))}();